VALUES
  ('disabled-8b44517b-moex-00044', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'essay', '行政程序法第 117 條規定：「違法行政處分於法定救濟期間經過後，
原處分機關得依職權為全部或一部之撤銷；其上級機關，亦得為之。
但有下列各款情形之一者，不得撤銷︰……。」請問：本條明文規
定，原處分機關不得撤銷違法行政處分之情形有那些？針對該行政
處分，如果當事人對之曾提起訴願及行政訴訟，最後被最高行政法院
駁回確定，但原處分機關後來發現，原行政處分確實有違法之處，是
否仍可依職權自行撤銷？其法理依據為何？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00045', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於法律保留原則之敘述，下列何者錯誤？', '["大學生退學處分事項，不得由大學自訂章則加以規範，而必須以法律定之", "人民依法律納稅為法律保留原則之展現", "違反行政法上義務之處罰，以行為時之法律或自治條例明文規定者為限", "公務人員退休年資之計算，屬法律保留之事項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00046', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '藥害救濟法第 13 條規定：「有下列各款情事之一者，不得申請藥害救濟 ：……九、常見且可預期之藥物不良反應。」關於本條規定，依司法院大 法官解釋意旨，下列敘述何者錯誤？', '["立法者以不確定法律概念規範藥害救濟申請之構成要件，有成立判斷餘 地之可能", "「常見」、「可預期」之意義，依一般人民日常生活與語言經驗，已屬 難以理解", "針對「藥物不良反應」，可透過醫師告知與藥袋標示或藥物仿單而具備 可預見性", "藥害救濟之審議於實務上累積諸多案例，因此，最終可由司法審查來加 以確認"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00047', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '依最高行政法院庭長法官聯席會議決議，訴願人依訴願法第2條規定提起 訴願，受理訴願機關未為決定前機關已作成行政處分，但非全部有利於訴 願人時，受理訴願機關應如何處理？', '["應依訴願聲明為不同之處理", "應依訴願法第82條第2項規定，以訴願為無理由予以駁回", "應續行訴願程序，對嗣後所為之行政處分併為實體審查", "應依訴願法第82條第2項規定，以訴願為不合法予以不受理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00048', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於行政機關之敘述，下列何者錯誤？', '["乃獨立之組織體，與內部單位有別", "屬於行使行政權之機關，與行使審判權之機關有別", "以行使公權力為限，不得從事私經濟行政", "行為之法律效果均歸屬於行政主體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00049', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於地方制度法上權限爭議與規範審查，下列敘述何者正確？', '["地方自治條例規範電子遊戲場業營業場所與國民小學之距離，不得逾越 中央法規之標準", "食品安全衛生管理法上動物殘留用藥安全容許量之管制標準，地方得訂 定較中央更嚴格之規範", "上下級地方自治團體間之權限爭議，應聲請憲法法庭為宣告違憲之判決", "自治法規被函告無效，地方自治團體經確定終局裁判，得聲請憲法法庭 為宣告違憲之判決"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00050', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '經濟部公告將「再生能源發電設備設置管理辦法」相關業務委由雲林縣辦 理。其行為之性質為何？', '["職務協助", "權限委託", "權限委任", "委辦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00051', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '下列行為發生爭議，何者應向行政法院提起救濟？', '["行政機關為新興建之辦公大樓添購相關設備", "公立醫院向民間廠商採購醫療器材之給付", "台灣自來水公司向自來水用戶收取水費", "衛生福利部中央健康保險署與醫事服務機構簽訂之特約履行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00052', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於公務人員之懲戒與懲處，下列敘述何者正確？', '["懲戒權具有司法權的性質", "懲處的法律依據為公務員懲戒法", "懲戒有功過相抵制度", "懲處不得先行停職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('disabled-8b44517b-moex-00053', 'disabled-8b44517b', 'disabled-8b44517b-moex-114-3082b5f1', 'sub-disabled-8b44517b-05', NULL, 'single_choice', '關於公用地役關係之敘述，下列何者錯誤？', '["既成道路之土地所有權，縱未移轉登記而仍為私人所有，私人亦不得於 道路上起造任何建築物", "私人土地長期供自然排水使用，且經歷年代久遠未曾中斷，一般人無復 記憶其確實使用起點，得認其已具公用地役關係", "主管機關於甲所有之既成道路上劃設停車格收取停車費，甲得向主管機 關請求返還所收取停車費之公法上不當得利", "既成道路喪失其原有功能時，主管機關得以對物之一般處分予以廢止"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:20+00:00", "source_pdf_sha1": "03b0ee471a0c", "answer_pdf_sha1": "a7faea101c05", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "302", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "勞工行政"}'::jsonb, NULL)
